#!/bin/bash
#
# Moonshine container initialization for a0 summon protocol.
# Runs inside containers to enable on-demand package summoning.
#
# Usage: docker run -e A0_FORGE_URL=... -v ~/.a0:/home/builder/.a0 image:tag
#

set -e

FORGE_URL="${A0_FORGE_URL:-https://registry.forgo.cloud}"
A0_DIR="${A0_CACHE_DIR:-$HOME/.a0}"
VERBOSE="${A0_VERBOSE:-0}"

log() {
  if [ "$VERBOSE" = "1" ]; then
    echo "[summon-init] $*" >&2
  fi
}

loginfo() {
  echo "[summon-init] $*" >&2
}

loginfo "Initializing a0 summon in container"
loginfo "Forge URL: $FORGE_URL"
loginfo "Cache: $A0_DIR"

# Ensure cache directories exist
mkdir -p "$A0_DIR/modules"
mkdir -p "$A0_DIR/cert-cache"
mkdir -p "$A0_DIR/.perf"
mkdir -p "$A0_DIR/cache/registry"

log "Cache directories initialized"

# Create .npmrc if needed
if [ ! -f "$HOME/.npmrc" ]; then
  cat > "$HOME/.npmrc" << EOF
registry=${FORGE_URL}/registry/npm/
cache=$A0_DIR/cache/npm

# Container-specific optimizations
fetch-timeout=120000
fetch-retries=3

# Parallel install
child-concurrency=8

# Shallow clone (if fetching from git)
depth=1
EOF
  loginfo "Created .npmrc with summon registry"
else
  log "Using existing .npmrc"
fi

# Set environment variables for optimal container performance
export A0_FORGE_URL="$FORGE_URL"
export A0_CACHE_DIR="$A0_DIR"
export A0_PREFETCH_ENABLED="${A0_PREFETCH_ENABLED:-1}"
export A0_WORKERS="${A0_WORKERS:-2}" # Conservative for containers (vs CPU count - 2)

log "Environment variables set for summon"

# Warmup: prefetch common dependencies if prefetch enabled
if [ "$A0_PREFETCH_ENABLED" = "1" ]; then
  loginfo "Prefetching common dependencies..."
  # In a real container, this would call summon or pnpm to warm the cache
  # For now, just log the intent
  log "Prefetch intent: react, typescript, @babel/core, lodash"
fi

loginfo "Container initialization complete"
loginfo "Ready for: a0 run <target> or pnpm install"
